<?php $__env->startSection('content'); ?><div class="card"><h2>My Orders</h2><div class="table-wrap"><table><thead><tr><th>Order</th><th>Game</th><th>Package</th><th>Amount</th><th>Payment</th><th>Status</th><th>Message</th></tr></thead><tbody><?php $__empty_1 = true; $__currentLoopData = $orders; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $o): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><tr><td><?php echo e($o->order_no); ?></td><td><?php echo e($o->game->name); ?></td><td><?php echo e($o->package->name); ?></td><td>₹<?php echo e(number_format($o->amount_minor/100,2)); ?></td><td><?php echo e(ucfirst($o->payment_mode)); ?></td><td><span class="badge badge-<?php echo e($o->order_status); ?>"><?php echo e(ucfirst(str_replace('_',' ',$o->order_status))); ?></span></td><td><?php echo e($o->message); ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="7">No orders found.</td></tr><?php endif; ?></tbody></table></div><?php echo e($orders->links()); ?></div><?php $__env->stopSection(); ?>

